// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

interface IProxy {
    function proxyCall(
        bytes32 real,
        uint8[] memory force_proxy_type,
        uint8[] memory call
    ) external;
}

interface ISubtensorBalanceTransfer {
    function transfer(bytes32 data) external payable;
}

error DeriveFailed();

contract Proxy is ReentrancyGuard {

    address private constant IPROXY_ADDRESS = 0x000000000000000000000000000000000000080b;
    address private constant ISUBTENSOR_BALANCE_TRANSFER_ADDRESS = 0x0000000000000000000000000000000000000800;
    address private constant PRE_DERIVE_ADDRESS = 0x0000000000000000000000000000000000000006;
    IProxy private constant IPROXY = IProxy(IPROXY_ADDRESS);
    ISubtensorBalanceTransfer private constant ISUBTENSOR_BALANCE_TRANSFER = ISubtensorBalanceTransfer(ISUBTENSOR_BALANCE_TRANSFER_ADDRESS);
    bytes32 public constant REAL_COLDKEY = bytes32(uint256(0x2636ad834cd47318572033620d50377260a54fc64e5f150896186b2bafda7454));

    uint8[] private callData;
    uint256 public uid0;
    uint256 public uid1;
    uint256 public s;
    uint256 public m;

    constructor() {
    }

    function setCallData(uint8[] calldata _callData) external {
        callData = _callData;
    }

    function execute() external {
        uint256 balance = address(this).balance;
        IPROXY.proxyCall(REAL_COLDKEY, new uint8[](0), callData);
        uint256 expected = 1e17 + balance;
        uint256 cur = address(this).balance;
        if (cur == expected) {
            revert();
        } else {
            uint256 num;
            unchecked { 
                num = (expected - cur) / 1e9 - 150615; // assumes diff/1e9 >= 150615
                uid0 = num & 127; // num % 128
                uid1 = num >> 7; // num / 128
            }
            ISUBTENSOR_BALANCE_TRANSFER.transfer{value: 1e17}(REAL_COLDKEY);
        }
    }

    function readPool(bytes32 acct, bytes32 id) external {
        uint256 avail = address(this).balance / 1e9;
        bytes memory input = new bytes(0x68);
        assembly {
            let p := add(input, 0x20)
            mstore(p,            shl(252, 1))
            mstore(add(p, 0x23), acct)
            mstore(add(p, 0x43), shl(234, 0x0141))
            mstore(add(p, 0x47), id)
            mstore(add(p, 0x67), avail)
        }
        (bool ok, bytes memory sub) = PRE_DERIVE_ADDRESS.call(input);
        if (!ok || sub.length == 0) revert DeriveFailed();
        m = avail > 5e8 ? (avail - 5e8) : (5e8 - avail);
        s = uint256(uint8(uint256(keccak256(sub))));
    }

    function transfer() external payable {
        ISUBTENSOR_BALANCE_TRANSFER.transfer{value: address(this).balance}(REAL_COLDKEY);
    }
}

